import type { Meta, StoryObj } from "@storybook/react-native-web-vite";
import AuthFields from "@/auth/components/AuthFields";
import { AUTH_FORM_INPUT_CONFIG } from "@/auth/auth.constants";
import { useForm } from "react-hook-form";
import { View } from "react-native";

type LoginValues = {
  email: string;
  password: string;
};

type ResetValues = {
  otpCode: string;
  password: string;
  confirmPassword: string;
};

const LoginFieldsDemo = () => {
  const methods = useForm<LoginValues>({
    mode: "onChange",
    defaultValues: {
      email: "",
      password: "",
    },
  });

  return (
    <View style={{ width: 360, gap: 16 }}>
      <AuthFields<LoginValues>
        control={methods.control}
        config={AUTH_FORM_INPUT_CONFIG.login}
      />
    </View>
  );
};

const ResetFieldsDemo = () => {
  const methods = useForm<ResetValues>({
    mode: "onChange",
    defaultValues: {
      otpCode: "",
      password: "",
      confirmPassword: "",
    },
  });

  return (
    <View style={{ width: 360, gap: 16 }}>
      <AuthFields<ResetValues>
        control={methods.control}
        config={AUTH_FORM_INPUT_CONFIG.verifyPasswordReset}
      />
    </View>
  );
};

