import type { Meta, StoryObj } from "@storybook/react-native-web-vite";
import { useEffect } from "react";
import { useForm } from "react-hook-form";
import PasswordInput from "@/components/PasswordInput";

type DemoValues = {
  password: string;
};

const DemoField = ({
  showError = false,
  defaultValue = "",
}: {
  showError?: boolean;
  defaultValue?: string;
}) => {
  const methods = useForm<DemoValues>({
    mode: "onChange",
    defaultValues: { password: defaultValue },
  });

  useEffect(() => {
    if (!showError) {
      return;
    }

    methods.setError("password", {
      type: "manual",
      message: "Password must be at least 8 characters.",
    });
  }, [methods, showError]);

  return (
    <PasswordInput<DemoValues>
      control={methods.control}
      name="password"
      label="Password"
      placeHolder="Enter your password"
    />
  );
};

const meta = {
  title: "Shared/PasswordInput",
  component: DemoField,
  tags: ["autodocs"],
  decorators: [
    (Story) => (
      <div style={{ width: 360 }}>
        <Story />
      </div>
    ),
  ],
  args: {
    showError: false,
    defaultValue: "",
  },
} satisfies Meta<typeof DemoField>;

export default meta;

type Story = StoryObj<typeof meta>;

